export const All = () => {
  const [showScrollArea, setShowScrollArea] = React.useState(true);
  const [alwaysShow, setAlwaysShow] = React.useState(false);
  const [scrollX, setScrollX] = React.useState(false);
  const [scrollY, setScrollY] = React.useState(true);
  const [virtual, setVirtual] = React.useState(false);

  const refresh = () => {
    setShowScrollArea(false);
    setTimeout(() => {
      setShowScrollArea(true);
    }, 200);
  };
  return (
    <>
      <Space>
        <Checkbox checked={alwaysShow} onCheckChange={checked => setAlwaysShow(checked)}>
          Always show Scrollbar
        </Checkbox>
        <Checkbox checked={virtual} onCheckChange={checked => setVirtual(checked)}>
          Virtual
        </Checkbox>
        <Checkbox checked={scrollX} onCheckChange={checked => setScrollX(checked)}>
          ScrollX
        </Checkbox>
        <Checkbox checked={scrollY} onCheckChange={checked => setScrollY(checked)}>
          ScrollY
        </Checkbox>
      </Space>

      <Divider />
      <Button type="primary" icon={<RefreshOutlined />} onClick={refresh}>
        Refresh
      </Button>
      <Divider />
      {showScrollArea && (
        <ScrollArea
          scrollX={scrollX}
          scrollY={scrollY}
          virtual={virtual}
          style={{
            ...horizontalSharedStyle,
            width: 400,
            padding: 20,
          }}
          showScrollBars={alwaysShow ? 'always' : 'whenScrolling'}
        >
          <div style={{ width: 500, background: 'orange', height: 20 }} />
          {longText}
        </ScrollArea>
      )}
    </>
  );
};

export const DynamicChildren = () => {
  const [toggled, setToggled] = React.useState(false);
  return (
    <>
      <Text as="div">
        收到过反馈，切换 children 会报错。因为 OverlayScrollbars 通过 js 操作 DOM 和 React 的更新产生冲突。
      </Text>
      <Button onClick={() => setToggled(!toggled)}>Toggle</Button>
      <ScrollArea virtual style={{ maxHeight: 300 }}>
        {toggled ? <h1>h1h11h1</h1> : <h2>h2 h2 h2</h2>}
      </ScrollArea>
    </>
  );
};

